mapper.select:
SELECT rule_snapshot FROM rule_history
WHERE rule_id = #{ruleId}
ORDER BY created_at DESC LIMIT 1

mapper.delete:
DELETE FROM rule_history
WHERE rule_id = #{ruleId}
AND id NOT IN (
    SELECT id FROM rule_history
    WHERE rule_id = #{ruleId}
    ORDER BY created_at DESC LIMIT #{keepCount}
)
